class RedisSession:
    def __init__(self, app, host='localhost', port=6379, db=0, key_prefix='session:'):
        self.app = app
        self.redis = redis.StrictRedis(host=host, port=port, db=db, decode_responses=True)
        self.key_prefix = key_prefix
        self.init_app()

    def init_app(self):
        self.app.session_interface = self

    def open_session(self, app, request):
        session_id = request.cookies.get(app.session_cookie_name)
        if session_id:
            session_data = self.redis.get(self.key_prefix + session_id)
            if session_data:
                return RedisSessionDict(session_id, self.redis, self.key_prefix, json.loads(session_data))
        return RedisSessionDict(None, self.redis, self.key_prefix)

    def save_session(self, app, session_dict, response):
        domain = self.get_cookie_domain(app)
        path = self.get_cookie_path(app)
        httponly = self.get_cookie_httponly(app)
        secure = self.get_cookie_secure(app)
        samesite = self.get_cookie_samesite(app)

        if not session_dict:
            if session_dict.modified:
                self.redis.delete(self.key_prefix + session_dict.sid)
                response.delete_cookie(app.session_cookie_name, domain=domain, path=path)
            return

        if not session_dict.sid:
            session_dict.sid = self.generate_sid()

        # If the session is empty and not modified, skip saving.
        # This handles cases where a session is created but nothing is added.
        if not session_dict and not session_dict.modified:
            return

        # Always save if modified or if it's a new session with data
        if session_dict.modified or session_dict.new:
            val = json.dumps(dict(session_dict))
            self.redis.setex(
                self.key_prefix + session_dict.sid,
                timedelta(days=app.permanent_session_lifetime.days),  # Example: 31 days
                val
            )

        response.set_cookie(
            app.session_cookie_name,
            session_dict.sid,
            expires=self.get_expiration_time(app, session_dict),
            httponly=httponly,
            domain=domain,
            path=path,
            secure=secure,
            samesite=samesite
        )

    def generate_sid(self):
        return str(time.time()) + str(hash(time.time()))

    # Helper methods to mirror Flask's SessionInterface behavior for cookie options
    def get_cookie_domain(self, app):
        return app.config.get("SESSION_COOKIE_DOMAIN")

    def get_cookie_path(self, app):
        return app.config.get("SESSION_COOKIE_PATH", "/")

    def get_cookie_httponly(self, app):
        return app.config.get("SESSION_COOKIE_HTTPONLY", True)

    def get_cookie_secure(self, app):
        return app.config.get("SESSION_COOKIE_SECURE", False)

    def get_cookie_samesite(self, app):
        return app.config.get("SESSION_COOKIE_SAMESITE", "Lax")

    def get_expiration_time(self, app, session_dict):
        if session_dict.permanent:
            return session_dict.permanent_session_lifetime
        return None


class RedisSessionDict(dict):
    def __init__(self, sid, redis_client, key_prefix, initial=None):
        super().__init__(initial or {})
        self.sid = sid
        self.redis = redis_client
        self.key_prefix = key_prefix
        self.modified = False
        self.new = initial is None
        self.permanent = True  # Sessions are permanent by default in this setup

    def __setitem__(self, key, value):
        super().__setitem__(key, value)
        self.modified = True

    def __delitem__(self, key):
        super().__delitem__(key)
        self.modified = True

    def clear(self):
        super().clear()
        self.modified = True

    def pop(self, key, default=None):
        value = super().pop(key, default)
        if key in self: # Only mark modified if key was actually present
            self.modified = True
        return value

    def update(self, other=None, **kwargs):
        super().update(other, **kwargs)
        self.modified = True


