def cache(ttl=60):
    def decorator(f):
        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = f.__name__ + ":" + json.dumps(args) + ":" + json.dumps(kwargs)
            cached_result = cache_redis_client.get(cache_key)

            if cached_result:
                print(f"Cache hit for key: {cache_key}")
                return json.loads(cached_result)

            print(f"Cache miss for key: {cache_key}. Executing function...")
            result = f(*args, **kwargs)
            cache_redis_client.setex(cache_key, ttl, json.dumps(result))
            return result
        return decorated_function
    return decorator


